export function Sidebar() {
  const { user, logout } = useAuth();
  const [location] = useLocation();
  const [isMobileMenuOpen, setIsMobileMenuOpen] = useState(false);

  if (!user) return null;

  const userNavigation = navigation[user.role] || [];

  const handleLogout = () => {
